#[test]
fn dna_hex_round_trip() {
    let hex_str = "";
    let bytes = hex::decode(hex_str).unwrap();
    let dna = starbreaker_chf::parse_dna(&bytes).unwrap();
    assert_eq!(dna.part_count, 12);
    assert_eq!(dna.face_parts.len(), 12);
    let written = starbreaker_chf::write_dna(&dna);
    assert_eq!(bytes, written);
}
